TEMPLATE = '<!DOCTYPE html>\n<html lang="zh-TW">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0,user-scalable=no">\n<title>乾媽智囊團</title>\n<style>\n:root{\n  --br:#6B4226;--brl:#8B5A3A;--brd:#4A2C18;--brbg:#FDF6F0;\n  --cr:#FAF0E6;--gold:#C9A96E;--tx:#2C1810;--txl:#6B4226;\n  --gray:#888;--bor:#E8D5C4;--wh:#fff;\n  --hh:48px;--fh:64px;\n  --cat-c:#8B6914;--cat-bg:#FFF8E1;\n}\nbody.dark{\n  --br:#C9A96E;--brl:#D4B87A;--brd:#E8D5A0;--brbg:#2A2018;\n  --cr:#1A1510;--gold:#C9A96E;--tx:#F0E6D8;--txl:#C9A96E;\n  --gray:#777;--bor:#3A2C1E;--wh:#231A10;\n  --cat-c:#E8C84A;--cat-bg:#2A2010;\n}\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\nhtml,body{height:100%;overflow:hidden}\nbody{font-family:\'Helvetica Neue\',\'PingFang TC\',\'Noto Sans TC\',sans-serif;background:var(--cr);color:var(--tx);touch-action:pan-y;transition:background .3s,color .3s}\n#hdr{position:fixed;top:0;left:0;right:0;z-index:200;height:var(--hh);background:var(--br);display:flex;align-items:center;justify-content:center;box-shadow:0 2px 8px rgba(0,0,0,.2)}\nbody.dark #hdr{background:#2A1A08}\n#hdr h1{color:var(--gold);font-size:16px;font-weight:700;letter-spacing:.05em}\n#dtog{position:absolute;right:12px;top:50%;transform:translateY(-50%);background:rgba(255,255,255,.12);border:1.5px solid rgba(255,255,255,.25);border-radius:20px;padding:4px 10px;color:var(--gold);font-size:13px;cursor:pointer}\n#ftr{position:fixed;bottom:0;left:0;right:0;z-index:200;height:var(--fh);background:var(--br);display:flex;flex-direction:column;align-items:center;justify-content:center;gap:4px;padding:6px 8px 4px;box-shadow:0 -2px 8px rgba(0,0,0,.2)}\nbody.dark #ftr{background:#2A1A08}\n.ftr-pills{display:flex;gap:7px;align-items:center}\n.ftr-hint{font-size:10px;color:rgba(201,169,110,0.6);letter-spacing:.02em}\n.np{padding:5px 12px;border-radius:20px;border:1.5px solid var(--gold);color:var(--gold);font-size:13px;font-weight:500;cursor:pointer;white-space:nowrap;transition:all .2s;user-select:none}\n.np.on{background:var(--gold);color:#4A2C18;font-weight:700}\n#pgs{position:fixed;top:var(--hh);bottom:var(--fh);left:0;right:0;overflow:hidden}\n.pg{position:absolute;top:0;bottom:0;left:0;right:0;overflow-y:auto;overflow-x:hidden;background:var(--cr);transition:transform .3s cubic-bezier(.4,0,.2,1);-webkit-overflow-scrolling:touch}\n.pg.hl{transform:translateX(-100%)}\n.pg.hr{transform:translateX(100%)}\n.pg.on{transform:translateX(0)}\n#pg0{padding:16px 14px 20px}\n.hgrid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px}\n.hcard{background:var(--wh);border-radius:14px;border:1.5px solid var(--bor);padding:14px;cursor:pointer;aspect-ratio:1;display:flex;flex-direction:column;position:relative;box-shadow:0 2px 8px rgba(107,66,38,.06);transition:transform .15s}\n.hcard:active{transform:scale(.97)}\n.hcard .hico{font-size:22px}\n.hcard .hlbl{font-size:13px;color:var(--txl);font-weight:600;margin-top:6px}\n.hcard .hnum{position:absolute;left:14px;bottom:12px;font-size:34px;font-weight:900;color:var(--br);line-height:1}\n.hcred{text-align:center;margin-top:4px}\n.cred-pill{display:inline-block;padding:5px 16px;border-radius:20px;border:1.5px solid #ccc;color:#999;font-size:11px}\n/* SEARCH */\n.sw{padding:10px 14px 6px;background:var(--cr);position:sticky;top:0;z-index:10;border-bottom:1px solid var(--bor)}\n.sr{position:relative;display:flex;align-items:center}\n.si{width:100%;padding:9px 34px 9px 13px;border-radius:24px;border:1.5px solid var(--bor);background:var(--wh);font-size:14px;color:var(--tx);outline:none;transition:border-color .2s}\n.si:focus{border-color:var(--br)}\n.sc{position:absolute;right:11px;color:var(--gray);font-size:15px;cursor:pointer;padding:4px;display:none;line-height:1}\n.sc.show{display:block}\n/* FILTERS */\n.fs{padding:6px 14px 2px}\n.fg{margin-bottom:3px}\n.ftog{display:flex;align-items:center;gap:5px;cursor:pointer;padding:5px 0;font-size:12px;color:var(--br);font-weight:600;user-select:none}\n.ftog .arr{font-size:9px;transition:transform .2s;display:inline-block}\n.ftog.op .arr{transform:rotate(90deg)}\n.fcnt{color:var(--gray);font-weight:400}\n.fal{color:var(--brl);font-size:11px;background:var(--brbg);padding:1px 7px;border-radius:8px}\n.cw{display:flex;flex-wrap:wrap;gap:5px;padding:5px 0 3px}\n.ch{padding:4px 11px;border-radius:16px;border:1.5px solid var(--bor);font-size:12px;color:var(--txl);cursor:pointer;background:var(--wh);transition:all .15s;white-space:nowrap}\n.ch.on{background:var(--br);color:var(--wh);border-color:var(--br)}\n.ch:active{opacity:.7}\n.clr-btn{margin:4px 0 2px;padding:4px 12px;border-radius:14px;border:1.5px solid #e08060;color:#e08060;font-size:11px;font-weight:600;cursor:pointer;background:var(--wh);display:inline-block}\n.clr-btn:active{background:#e08060;color:#fff}\n/* LIST */\n.lc{padding:4px 14px 20px}\n.rc{font-size:12px;color:var(--gray);margin-bottom:6px;display:flex;justify-content:space-between;align-items:center}\n.top-btn{font-size:11px;color:var(--br);background:var(--brbg);border:1px solid var(--bor);border-radius:12px;padding:3px 10px;cursor:pointer}\n/* ITEM CARDS */\n.ic{background:var(--wh);border-radius:12px;border:1.5px solid var(--bor);margin-bottom:9px;overflow:hidden;box-shadow:0 1px 4px rgba(107,66,38,.05)}\n.ih{padding:11px 13px 9px;cursor:pointer;display:flex;justify-content:space-between;align-items:flex-start;gap:8px}\n.ih:active{background:rgba(107,66,38,.03)}\n.in{font-size:15px;font-weight:700;color:var(--tx);line-height:1.3}\n.im{font-size:11px;color:var(--gray);margin-top:3px;display:flex;gap:4px;flex-wrap:wrap;align-items:center}\n.mcat{color:var(--cat-c);font-weight:600;background:var(--cat-bg);padding:1px 7px;border-radius:8px;font-size:11px}\n.ieb{color:var(--br);font-size:13px;flex-shrink:0;padding-top:2px}\n.idet{border-top:1px solid var(--bor);padding:11px 13px;display:none}\n.idet.op{display:block}\n.rev{font-size:13px;color:var(--tx);line-height:1.6;white-space:pre-wrap;margin-bottom:10px}\n.lnks{display:flex;flex-wrap:wrap;gap:7px;margin-bottom:8px}\n.lnk{padding:5px 12px;border-radius:16px;font-size:12px;font-weight:600;text-decoration:none;display:inline-block;transition:all .15s;border:1.5px solid}\n.lnk-g{border-color:#D32F2F;color:#D32F2F}.lnk-g:active{background:#D32F2F;color:#fff}\n.lnk-f{border-color:#1877F2;color:#1877F2}.lnk-f:active{background:#1877F2;color:#fff}\n.lnk-i{border-color:#E4621B;color:#E4621B}.lnk-i:active{background:#E4621B;color:#fff}\n.lnk-w{border-color:#888;color:#888}.lnk-w:active{background:#888;color:#fff}\n/* COLLAPSIBLE SECTIONS */\n.csec{margin-top:8px;border-top:1px dashed var(--bor);padding-top:7px}\n.ctog{display:flex;align-items:center;gap:6px;cursor:pointer;font-size:12px;font-weight:700;color:var(--br);padding:3px 0;user-select:none}\n.ctog .carr{font-size:9px;transition:transform .2s;display:inline-block}\n.ctog.op .carr{transform:rotate(90deg)}\n.cbody{display:none;padding-top:5px}\n.cbody.op{display:block}\n.ci{font-size:12px;color:var(--txl);padding:4px 0;cursor:pointer;border-bottom:1px solid rgba(107,66,38,.05);display:flex;gap:5px;align-items:center;line-height:1.4}\n.ci:last-child{border-bottom:none}\n.ci:active{color:var(--br)}\n.ci-sq{width:6px;height:6px;background:var(--br);border-radius:1px;flex-shrink:0;margin-top:3px}\n.ci-cat{color:var(--cat-c);font-size:10px;background:var(--cat-bg);padding:1px 5px;border-radius:6px;margin-left:4px;font-weight:600}\n.nb-none{font-size:12px;color:var(--gray);font-style:italic;padding:3px 0}\n/* Q CARDS */\n.qc{background:var(--wh);border-radius:12px;border:1.5px solid var(--bor);margin-bottom:8px;padding:11px 13px;box-shadow:0 1px 4px rgba(107,66,38,.05)}\n.qc.hot{border-color:#ff4444;border-width:2px}\n.qt{font-size:14px;font-weight:600;color:var(--tx);line-height:1.4;display:flex;align-items:flex-start;gap:7px}\n.qsq{width:8px;height:8px;background:var(--br);border-radius:2px;flex-shrink:0;margin-top:4px}\n.qr2{display:flex;gap:8px;align-items:center;margin-top:4px;padding-left:15px;flex-wrap:wrap}\n.qdate{font-size:11px;color:var(--gray)}\n.qhot{font-size:11px;padding:2px 8px;border-radius:10px;border:1.5px solid #ff4444;color:#ff4444;font-weight:600}\n.qtags{display:flex;flex-wrap:wrap;gap:4px;margin-top:5px;padding-left:15px}\n.qtag{padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600}\n.qtag-n{background:#E8F4FF;color:#1565C0}\n.qtag-w{background:#E8F5E9;color:#2E7D32}\n.qtag-s{background:#FFF3E0;color:#E65100}\n.qtag-e{background:#F3E5F5;color:#6A1B9A}\n.qtag-i{background:#FCE4EC;color:#AD1457}\n.qtag-t{background:var(--brbg);color:var(--br)}\n.empty{text-align:center;padding:40px 20px;color:var(--gray);font-size:14px}\n\n/* NOTICE */\n.notice-box{margin:0 0 12px;padding:12px 14px;border-radius:12px;border:1.5px solid var(--bor);background:var(--wh);font-size:12px;color:var(--tx);line-height:1.8}\n.notice-red{color:#cc0000;font-weight:700}\n/* VIS BADGE */\n.vis-badge{font-size:11px;color:rgba(255,255,255,0.85);background:rgba(0,0,0,.3);padding:2px 8px;border-radius:10px;white-space:nowrap;pointer-events:none;position:absolute;left:12px;top:50%;transform:translateY(-50%)}\n/* HOME */\n.home-inner{max-width:480px;margin:0 auto;padding:16px 14px 20px}\n/* GP */\n.gp-card{background:var(--wh);border-radius:14px;border:1.5px solid var(--bor);padding:14px;margin-bottom:12px;box-shadow:0 2px 8px rgba(107,66,38,.06)}\n.gp-header{display:flex;align-items:center;gap:10px;cursor:pointer}\n.gp-ico{font-size:22px}.gp-info{flex:1}\n.gp-title{font-size:13px;font-weight:600;color:var(--txl)}\n.gp-num{font-size:28px;font-weight:900;color:var(--br);line-height:1}\n.gp-arr{color:var(--br);font-size:13px;transition:transform .2s;flex-shrink:0}\n.gp-arr.op{transform:rotate(180deg)}\n.gp-body{display:none;margin-top:10px;border-top:1px solid var(--bor);padding-top:10px}\n.gp-body.op{display:block}\n.gp-item{border:1px solid var(--bor);border-radius:10px;padding:10px 12px;margin-bottom:8px;background:var(--brbg)}\n.gp-item:last-child{margin-bottom:0}\n.gp-item-name{font-size:14px;font-weight:700;color:var(--tx);margin-bottom:4px}\n.gp-item-row{font-size:11px;color:var(--gray);margin-top:2px;display:flex;gap:6px;flex-wrap:wrap;align-items:center}\n.gp-cd{font-size:12px;font-weight:700;padding:2px 8px;border-radius:8px;background:#FFF0E6;color:#C06020}\n.gp-cd.urg{background:#FFE6E6;color:#C02020}\n.gp-link{color:var(--br);font-size:12px;text-decoration:underline;font-weight:600}\n.bottom-cred{text-align:center;padding:6px 0 4px}\n/* FILTER */\n.fg-hrow{display:flex;align-items:center;justify-content:space-between}\n.clr-inline{font-size:11px;color:#e08060;border:1.5px solid #e08060;border-radius:12px;padding:3px 10px;cursor:pointer;background:var(--wh);font-weight:600;white-space:nowrap;flex-shrink:0}\n.clr-inline:active{background:#e08060;color:#fff}\n/* DARK MODE */\nbody.dark #ftr{background:#1A0E05}\nbody.dark .np{border-color:#C9A96E;color:#C9A96E}\nbody.dark .np.on{background:#C9A96E;color:#1A0E05;font-weight:700}\nbody.dark .ftr-hint{color:rgba(201,169,110,0.5)}\nbody.dark .hcard{background:#2A1A08;border-color:#3A2C1E}\nbody.dark .hcard .hnum{color:#C9A96E}\nbody.dark .hcard .hlbl{color:#C9A96E}\nbody.dark .ic{background:#2A1A08;border-color:#3A2C1E}\nbody.dark .qc{background:#2A1A08;border-color:#3A2C1E}\nbody.dark .gp-card{background:#2A1A08;border-color:#3A2C1E}\nbody.dark .gp-item{background:#1A1005;border-color:#3A2C1E}\nbody.dark .ch{background:#2A1A08;border-color:#3A2C1E;color:#C9A96E}\nbody.dark .ch.on{background:#C9A96E;color:#1A0E05;border-color:#C9A96E}\nbody.dark .si{background:#2A1A08;border-color:#3A2C1E;color:#F0E6D8}\nbody.dark .clr-inline{background:#2A1A08}\nbody.dark .cred-pill{border-color:#3A2C1E;color:#777}\nbody.dark .notice-box{background:#2A1A08;border-color:#3A2C1E}\nbody.dark .notice-red{color:#ff6b6b}\n/* CITY BADGE */\n.meta-city{font-size:11px;color:#1565C0;background:#E8F4FF;padding:1px 7px;border-radius:8px;font-weight:600}\nbody.dark .meta-city{color:#90CAF9;background:#0D2137}\n/* REF BADGE - brown bordered, no underline */\n.ref-badge{display:inline-block;font-size:11px;color:var(--br);border:1.5px solid var(--bor);border-radius:8px;padding:1px 8px;margin:1px 2px;background:var(--brbg)}\nbody.dark .ref-badge{border-color:#5A3C1E;background:#2A1A08}\n/* NOTION NOTICE - no underline */\n.notion-notice{display:inline-block;color:#cc0000;font-weight:700;font-size:12px;padding:3px 8px;border:1.5px solid #cc0000;border-radius:8px}\nbody.dark .notion-notice{color:#ff6b6b;border-color:#ff6b6b}\n/* NEARBY */\n.nb-none{font-size:12px;color:var(--gray);font-style:italic;padding:3px 0}\n.nb-more{font-size:11px;color:var(--br);cursor:pointer;padding:3px 0;font-weight:600}\n/* COLLAPSE */\n.csec{margin-top:8px;border-top:1px dashed var(--bor);padding-top:7px}\n.ctog{display:flex;align-items:center;gap:6px;cursor:pointer;font-size:12px;font-weight:700;color:var(--br);padding:3px 0;user-select:none}\n.ctog .carr{font-size:9px;transition:transform .2s;display:inline-block}\n.ctog.op .carr{transform:rotate(90deg)}\n.cbody{display:none;padding-top:5px}\n.cbody.op{display:block}\n.ci{font-size:12px;color:var(--txl);padding:4px 0;cursor:pointer;border-bottom:1px solid rgba(107,66,38,.05);display:flex;gap:5px;align-items:center;line-height:1.4;flex-wrap:wrap}\n.ci:last-child{border-bottom:none}\n.ci:active{color:var(--br)}\n.ci-sq{width:6px;height:6px;background:var(--br);border-radius:1px;flex-shrink:0;margin-top:3px}\n.ci-cat{color:var(--cat-c);font-size:10px;background:var(--cat-bg);padding:1px 5px;border-radius:6px;margin-left:2px;font-weight:600;flex-shrink:0}\n/* LOCATION label in ci rows (gray) */\n.ci-loc{font-size:10px;color:var(--gray);margin-left:2px;flex-shrink:0}\n\n/* MAX WIDTH for all pages on desktop */\n.sw,.fs,.lc{max-width:640px;margin-left:auto;margin-right:auto}\n.sw{padding-left:14px;padding-right:14px}\n</style>\n</head>\n<body>\n<script id="dbdata" type="application/json">DATA_PLACEHOLDER</script>\n<div id="hdr" style="position:fixed;top:0;left:0;right:0;z-index:200;height:var(--hh);background:var(--br);display:flex;align-items:center;justify-content:center;box-shadow:0 2px 8px rgba(0,0,0,.2)">\n  <h1 style="color:var(--gold);font-size:16px;font-weight:700;letter-spacing:.05em">乾媽智囊團</h1>\n</div>\n<div id="pgs">\n  <div class="pg on" id="pg0">\n    <div class="home-inner">\n      <div class="notice-box" id="notice-box" style="position:relative"><button onclick="document.getElementById(\'notice-box\').style.display=\'none\'" style="position:absolute;top:6px;right:8px;background:none;border:none;font-size:14px;cursor:pointer;color:var(--gray);line-height:1">✕</button><p>• 因notion不方便手機操作，故用AI做了網站，僅有收錄推薦的店家，無對話截圖，完整內容請至notion版乾媽智囊團</p><p class="notice-red">• notion版乾媽智囊團僅提供給實名制的乾媽群，並未提供給未實名制的團購群也不開放索取</p></div>\n      <div id="hgrid" class="hgrid" style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px"></div>\n      <div class="gp-card">\n        <div class="gp-header" onclick="togGP()">\n          <div class="gp-ico">🛒</div>\n          <div class="gp-info"><div class="gp-title">目前團購</div><div class="gp-num" id="gp-count">0</div></div>\n          <div class="gp-arr" id="gp-arr">▼</div>\n        </div>\n        <div class="gp-body" id="gp-body"></div>\n      </div>\n      <div class="bottom-cred"><span class="cred-pill">BY 新北三重-Alice wang1️⃣🌰</span></div>\n    </div>\n  </div>\n  <div class="pg hr" id="pg1">\n    <div class="sw"><div class="sr">\n      <input class="si" id="si-q" placeholder="搜尋問題..." oninput="onSI(\'q\')">\n      <span class="sc" id="sc-q" onclick="clearSI(\'q\')">✕</span>\n    </div></div>\n    <div style="font-size:11px;color:var(--gray);padding:3px 14px 0;max-width:640px;margin-left:auto;margin-right:auto">點一下可選取，再點一下取消選取</div>\n    <div class="fs" id="fs-q"></div>\n    <div class="lc">\n      <div class="rc"><span id="rc-q"></span></div>\n      <div id="ql"></div>\n      <div style="text-align:center;padding:12px 0 4px"><span class="top-btn" onclick="backTop(\'pg1\')">⬆ 回到頂端</span></div>\n    </div>\n  </div>\n  <div class="pg hr" id="pg2">\n    <div class="sw">\n      <div class="sr">\n        <input class="si" id="si-f" placeholder="搜尋美食..." oninput="onSI(\'f\')">\n        <span class="sc" id="sc-f" onclick="clearSI(\'f\')">✕</span>\n      </div>\n    </div>\n    <div style="font-size:11px;color:var(--gray);padding:3px 14px 0;max-width:640px;margin-left:auto;margin-right:auto">點一下可選取，再點一下取消選取</div>\n    <div class="fs" id="fs-f"></div>\n    <div class="lc">\n      <div class="rc"><span id="rc-f"></span></div>\n      <div id="fl"></div>\n      <div style="text-align:center;padding:12px 0 4px"><span class="top-btn" onclick="backTop(\'pg2\')">⬆ 回到頂端</span></div>\n    </div>\n  </div>\n  <div class="pg hr" id="pg3">\n    <div class="sw">\n      <div class="sr">\n        <input class="si" id="si-h" placeholder="搜尋住宿..." oninput="onSI(\'h\')">\n        <span class="sc" id="sc-h" onclick="clearSI(\'h\')">✕</span>\n      </div>\n    </div>\n    <div style="font-size:11px;color:var(--gray);padding:3px 14px 0;max-width:640px;margin-left:auto;margin-right:auto">點一下可選取，再點一下取消選取</div>\n    <div class="fs" id="fs-h"></div>\n    <div class="lc">\n      <div class="rc"><span id="rc-h"></span></div>\n      <div id="hl"></div>\n      <div style="text-align:center;padding:12px 0 4px"><span class="top-btn" onclick="backTop(\'pg3\')">⬆ 回到頂端</span></div>\n    </div>\n  </div>\n  <div class="pg hr" id="pg4">\n    <div class="sw">\n      <div class="sr">\n        <input class="si" id="si-s" placeholder="搜尋景點..." oninput="onSI(\'s\')">\n        <span class="sc" id="sc-s" onclick="clearSI(\'s\')">✕</span>\n      </div>\n    </div>\n    <div style="font-size:11px;color:var(--gray);padding:3px 14px 0;max-width:640px;margin-left:auto;margin-right:auto">點一下可選取，再點一下取消選取</div>\n    <div class="fs" id="fs-s"></div>\n    <div class="lc">\n      <div class="rc"><span id="rc-s"></span></div>\n      <div id="sl"></div>\n      <div style="text-align:center;padding:12px 0 4px"><span class="top-btn" onclick="backTop(\'pg4\')">⬆ 回到頂端</span></div>\n    </div>\n  </div>\n</div>\n<div id="ftr" style="position:fixed;bottom:0;left:0;right:0;z-index:200;background:var(--br);display:flex;flex-direction:column;align-items:center;justify-content:center;gap:4px;padding:6px 8px 4px;box-shadow:0 -2px 8px rgba(0,0,0,.2)">\n  <div class="ftr-pills">\n    <div class="np on" data-p="0" onclick="npClick(0)">首頁</div>\n    <div class="np" data-p="1" onclick="npClick(1)">問題</div>\n    <div class="np" data-p="2" onclick="npClick(2)">美食</div>\n    <div class="np" data-p="3" onclick="npClick(3)">住宿</div>\n    <div class="np" data-p="4" onclick="npClick(4)">景點</div>\n  </div>\n  <div class="ftr-hint">點一下切換頁面（也可左右滑動），點兩下回到頁面頂端</div>\n</div>\n<script>// 乾媽智囊團 - Main JS\nconst DB=JSON.parse(document.getElementById(\'dbdata\').textContent);\nconst Q=DB.q,F=DB.f,H=DB.h,S=DB.s;\n\nconst REGION_ORDER=[\'北部\',\'西部\',\'南部\',\'東部\',\'離島\'];\nconst REGIONS={\n  \'北部\':[\'基隆\',\'台北\',\'新北\',\'桃園\',\'新竹\',\'宜蘭\'],\n  \'西部\':[\'苗栗\',\'台中\',\'彰化\',\'南投\'],\n  \'南部\':[\'雲林\',\'嘉義\',\'台南\',\'高雄\',\'屏東\',\'澎湖\'],\n  \'東部\':[\'花蓮\',\'台東\'],\n  \'離島\':[\'金門\',\'馬祖\'],\n};\nconst CITY_ORDER=[];\nREGION_ORDER.forEach(r=>REGIONS[r].forEach(c=>{if(!CITY_ORDER.includes(c))CITY_ORDER.push(c)}));\nconst CITY_REGION={};\nObject.entries(REGIONS).forEach(([r,cs])=>cs.forEach(c=>CITY_REGION[c]=r));\nconst REGION_CLS={\'北部\':\'n\',\'西部\':\'w\',\'南部\':\'s\',\'東部\':\'e\',\'離島\':\'i\'};\nconst LOC_TAGS=new Set([...Object.values(REGIONS).flat(),\'出國\',\'日本\',\'韓國\',\'泰國\',\'歐洲\',\'港澳\']);\nconst TOPIC_PRI=[\'美食\',\'住宿\',\'旅遊\'];\n\nconst CAT={\n  \'A.小吃\':\'小吃\',\'B.餐廳\':\'餐廳\',\'C.甜點\':\'甜點\',\'D.咖啡廳\':\'咖啡廳\',\n  \'E.火鍋類\':\'火鍋\',\'F.燒肉\':\'燒肉\',\'G.牛排\':\'牛排\',\'H.鐵板燒\':\'鐵板燒\',\n  \'I.早午餐\':\'早午餐\',\'J.麵包西餅店\':\'麵包甜點\',\'K.海鮮\':\'海鮮\',\n  \'L.中式糕餅\':\'中式糕餅\',\'M.飲料\':\'飲料\',\'N.炸物\':\'炸物\',\'O.冰品\':\'冰品\',\n  \'P.日式\':\'日式\',\'Q.韓式\':\'韓式\',\'R.義式\':\'義式\',\'S.泰式\':\'泰式\',\n  \'T.港式\':\'港式\',\'U.伴手禮\':\'伴手禮\',\'V.餐酒館\':\'餐酒館\',\'W.居酒屋\':\'居酒屋\',\n  \'X.早餐\':\'早餐\',\'Y.喜餅/彌月\':\'喜餅彌月\',\'Z.素食\':\'素食\',\'Z1.酒吧\':\'酒吧\',\'Z2.其他\':\'其他\'\n};\nconst CAT_REV={};\nObject.entries(CAT).forEach(([k,v])=>CAT_REV[v]=k);\n\n// ===== INDICES =====\nconst DIST_IDX={};\nfunction addDI(arr,key){\n  arr.forEach(x=>{\n    const city=(x.city_tags&&x.city_tags.length)?x.city_tags[0]:(x.city||\'\').split(\',\')[0].trim();\n    const dist=x.district||\'\';\n    if(!city||!dist||dist===\'有分店\')return;\n    const k=city+\':\'+dist;\n    if(!DIST_IDX[k])DIST_IDX[k]={f:[],h:[],s:[]};\n    DIST_IDX[k][key].push(x);\n  });\n}\naddDI(F,\'f\');addDI(H,\'h\');addDI(S,\'s\');\n\nfunction buildDM(arr){\n  const m={};\n  arr.forEach(x=>{\n    const cities=x.city_tags&&x.city_tags.length?x.city_tags:[(x.city||\'\').split(\',\')[0].trim()];\n    const dist=x.district;\n    if(!dist||dist===\'有分店\')return;\n    cities.forEach(city=>{\n      if(!city)return;\n      if(!m[city])m[city]={};\n      if(!m[city][dist])m[city][dist]=[];\n      m[city][dist].push(x);\n    });\n  });\n  return m;\n}\nconst FDM=buildDM(F),HDM=buildDM(H),SDM=buildDM(S);\n\nfunction buildCatMap(arr){\n  const m={};\n  arr.forEach(x=>{\n    if(!x.cat)return;\n    const cities=x.city_tags&&x.city_tags.length?x.city_tags:[(x.city||\'\').split(\',\')[0].trim()];\n    cities.forEach(city=>{\n      if(!city)return;\n      if(!m[city])m[city]=new Set();\n      m[city].add(x.cat);\n    });\n  });\n  return m;\n}\nconst F_CAT_MAP=buildCatMap(F);\n\n// ===== STATE =====\nlet curPg=0;\nconst PGS=[\'pg0\',\'pg1\',\'pg2\',\'pg3\',\'pg4\'];\nconst ST={\n  q:{loc:\'\',topic:\'\'},\n  f:{city:\'\',dist:\'\',cat:\'\'},\n  h:{city:\'\',dist:\'\'},\n  s:{city:\'\',dist:\'\'}\n};\nconst INITED={q:0,f:0,h:0,s:0};\nlet isDark=0;\nconst REND={f:[],h:[],s:[]};\n\n// ===== DARK MODE =====\nfunction toggleDark(){\n  isDark=!isDark;\n  document.body.classList.toggle(\'dark\',isDark);\n}\n\n// ===== DOUBLE TAP NAV =====\nconst _lastTap={};\nfunction npClick(i){\n  const now=Date.now();\n  if(_lastTap[i]&&now-_lastTap[i]<400){\n    const el=document.getElementById(PGS[i]);\n    if(el)el.scrollTop=0;\n    _lastTap[i]=0;\n    return;\n  }\n  _lastTap[i]=now;\n  goPage(i);\n}\n\n// ===== NAVIGATION =====\nfunction goPage(i){\n  const prev=curPg;curPg=i;\n  PGS.forEach((id,j)=>{\n    const el=document.getElementById(id);\n    el.className=\'pg \'+(j===i?\'on\':j<i?\'hl\':\'hr\');\n  });\n  document.querySelectorAll(\'.np\').forEach(p=>p.classList.toggle(\'on\',+p.dataset.p===i));\n  if(prev!==i){\n    const pk=[null,\'q\',\'f\',\'h\',\'s\'][prev];\n    if(pk&&pk!==\'q\')clearFilters(pk,false);\n  }\n  const k=[null,\'q\',\'f\',\'h\',\'s\'][i];\n  if(k&&!INITED[k]){INITED[k]=1;window[\'init_\'+k]();}\n  if(typeof onPageVisit===\'function\')setTimeout(()=>onPageVisit(i),50);\n}\n\nlet tx=0,ty=0;\ndocument.getElementById(\'pgs\').addEventListener(\'touchstart\',e=>{tx=e.touches[0].clientX;ty=e.touches[0].clientY},{passive:true});\ndocument.getElementById(\'pgs\').addEventListener(\'touchend\',e=>{\n  const dx=e.changedTouches[0].clientX-tx,dy=e.changedTouches[0].clientY-ty;\n  if(Math.abs(dx)>65&&Math.abs(dx)>Math.abs(dy)*1.5){\n    if(dx<0&&curPg<4)goPage(curPg+1);\n    else if(dx>0&&curPg>0)goPage(curPg-1);\n  }\n},{passive:true});\n\nfunction clearFilters(type,refilter=true){\n  Object.keys(ST[type]).forEach(k=>ST[type][k]=\'\');\n  if(!refilter)return;\n  if(type===\'f\'){rebuildFSub();filterF();}\n  else if(type===\'h\'){rebuildHSub();filterH();}\n  else if(type===\'s\'){rebuildSSub();filterS();}\n  else filterQ();\n  document.querySelectorAll(\'[id^="fc-\'+type+\'"]\').forEach(el=>el.querySelectorAll(\'.ch\').forEach(c=>c.classList.remove(\'on\')));\n  document.querySelectorAll(\'[id^="ft-\'+type+\'"]\').forEach(el=>{const l=el.querySelector(\'.fal\');if(l)l.remove();});\n}\n\n// ===== SEARCH =====\nfunction onSI(t){\n  const inp=document.getElementById(\'si-\'+t);\n  document.getElementById(\'sc-\'+t).classList.toggle(\'show\',inp.value.length>0);\n  ({q:filterQ,f:filterF,h:filterH,s:filterS})[t]();\n}\nfunction clearSI(t){\n  document.getElementById(\'si-\'+t).value=\'\';\n  document.getElementById(\'sc-\'+t).classList.remove(\'show\');\n  ({q:filterQ,f:filterF,h:filterH,s:filterS})[t]();\n}\n\n// ===== SAFE ATTR: encode for use inside HTML attribute values =====\n// Use data attributes + JS to avoid escaping issues in onclick\nfunction esc(s){if(!s)return\'\';return String(s).replace(/&/g,\'&amp;\').replace(/</g,\'&lt;\').replace(/>/g,\'&gt;\').replace(/"/g,\'&quot;\');}\nfunction escAttr(s){if(!s)return\'\';return String(s).replace(/&/g,\'&amp;\').replace(/"/g,\'&quot;\');}\n\n// ===== FILTER BUILDER =====\nfunction mkFG(type,key,title,chips,active){\n  const fid=\'ft-\'+type+\'-\'+key,cid=\'fc-\'+type+\'-\'+key;\n  const al=active?\'<span class="fal">\'+esc(active)+\'</span>\':\'\';\n  const rows=chips.map(c=>\'<span class="ch\'+(c===active?\' on\':\'\')+\'" data-type="\'+type+\'" data-key="\'+key+\'" data-val="\'+escAttr(c)+\'" onclick="selChEl(this)">\'+esc(c)+\'</span>\').join(\'\');\n  return \'<div class="fg">\'\n    +\'<div class="ftog" id="\'+fid+\'" onclick="togF(\\\'\'+cid+\'\\\',\\\'\'+fid+\'\\\')">\'\n    +\'<span class="arr">▶</span><span>\'+title+\'</span>\'\n    +\'<span class="fcnt">(\'+chips.length+\')</span>\'+al\n    +\'</div>\'\n    +\'<div id="\'+cid+\'" style="display:none"><div class="cw">\'+rows+\'</div></div>\'\n    +\'</div>\';\n}\nfunction mkFGwithClr(type,key,title,chips,active){\n  const fid=\'ft-\'+type+\'-\'+key,cid=\'fc-\'+type+\'-\'+key;\n  const al=active?\'<span class="fal">\'+esc(active)+\'</span>\':\'\';\n  const rows=chips.map(c=>\'<span class="ch\'+(c===active?\' on\':\'\')+\'" data-type="\'+type+\'" data-key="\'+key+\'" data-val="\'+escAttr(c)+\'" onclick="selChEl(this)">\'+esc(c)+\'</span>\').join(\'\');\n  return \'<div class="fg">\'\n    +\'<div class="fg-hrow">\'\n    +\'<div class="ftog" id="\'+fid+\'" onclick="togF(\\\'\'+cid+\'\\\',\\\'\'+fid+\'\\\')">\'\n    +\'<span class="arr">▶</span><span>\'+title+\'</span>\'\n    +\'<span class="fcnt">(\'+chips.length+\')</span>\'+al\n    +\'</div>\'\n    +\'<span class="clr-inline" data-type="\'+type+\'" onclick="clearFilters(this.dataset.type)">清除篩選</span>\'\n    +\'</div>\'\n    +\'<div id="\'+cid+\'" style="display:none"><div class="cw">\'+rows+\'</div></div>\'\n    +\'</div>\';\n}\nfunction togF(cid,fid){\n  const col=document.getElementById(cid),tog=document.getElementById(fid);\n  const op=col.style.display===\'none\';\n  col.style.display=op?\'block\':\'none\';\n  tog.classList.toggle(\'op\',op);\n}\n// Use data attributes - no string escaping in onclick needed\nfunction selChEl(el){\n  const type=el.dataset.type,key=el.dataset.key,val=el.dataset.val;\n  selCh(type,key,val,el);\n}\nfunction selCh(type,key,val,el){\n  const wasOn=el.classList.contains(\'on\');\n  el.closest(\'[id^="fc-"]\').querySelectorAll(\'.ch\').forEach(c=>c.classList.remove(\'on\'));\n  const nv=wasOn?\'\':val;\n  if(!wasOn)el.classList.add(\'on\');\n  const tog=document.getElementById(\'ft-\'+type+\'-\'+key);\n  if(tog){\n    const old=tog.querySelector(\'.fal\');\n    if(old)old.remove();\n    if(nv){const s=document.createElement(\'span\');s.className=\'fal\';s.textContent=nv;tog.appendChild(s);}\n  }\n  ST[type][key]=nv;\n  if(type===\'q\'){if(key===\'loc\')updateQTopicChips(nv);filterQ();}\n  else if(type===\'f\'){\n    if(key===\'city\'){clearSI(\'f\');ST.f.dist=\'\';ST.f.cat=\'\';rebuildFSub(nv);}\n    filterF();\n  }\n  else if(type===\'h\'){if(key===\'city\'){clearSI(\'h\');ST.h.dist=\'\';rebuildHSub(nv);}filterH();}\n  else if(type===\'s\'){if(key===\'city\'){clearSI(\'s\');ST.s.dist=\'\';rebuildSSub(nv);}filterS();}\n}\n\nfunction getCities(arr){\n  const s=new Set();\n  arr.forEach(x=>{\n    const cities=x.city_tags&&x.city_tags.length?x.city_tags:[(x.city||\'\').split(\',\')[0].trim()];\n    cities.forEach(c=>{if(c&&c!==\'有分店\')s.add(c);});\n  });\n  return CITY_ORDER.filter(c=>s.has(c));\n}\n\n// ===== COLLAPSE =====\nfunction mkCollapse(id,title,count,content){\n  return \'<div class="csec">\'\n    +\'<div class="ctog" id="ctog-\'+id+\'" onclick="togC(\\\'\'+id+\'\\\')">\'\n    +\'<span class="carr">▶</span><span>\'+title+\'</span>\'\n    +\'<span style="color:var(--gray);font-weight:400;font-size:11px;margin-left:3px">(\'+count+\')</span>\'\n    +\'</div>\'\n    +\'<div class="cbody" id="cbody-\'+id+\'">\'+content+\'</div>\'\n    +\'</div>\';\n}\nfunction togC(id){\n  const b=document.getElementById(\'cbody-\'+id),t=document.getElementById(\'ctog-\'+id);\n  if(!b)return;\n  const op=b.classList.toggle(\'op\');\n  t.classList.toggle(\'op\',op);\n}\n\n// ===== Q PAGE =====\nfunction init_q(){\n  const locs=[...LOC_TAGS].filter(t=>Q.some(x=>x.tags.includes(t)));\n  const locOrd=CITY_ORDER.filter(c=>locs.includes(c));\n  locs.filter(t=>!locOrd.includes(t)).forEach(t=>locOrd.push(t));\n  const topicSet=new Set();\n  Q.forEach(x=>x.tags.forEach(t=>{if(!LOC_TAGS.has(t))topicSet.add(t)}));\n  const topOrd=[];\n  TOPIC_PRI.forEach(t=>{if(topicSet.has(t))topOrd.push(t)});\n  [...topicSet].filter(t=>!topOrd.includes(t)).sort().forEach(t=>topOrd.push(t));\n  document.getElementById(\'fs-q\').innerHTML=\n    mkFGwithClr(\'q\',\'loc\',\'地區\',locOrd,ST.q.loc)\n    +mkFG(\'q\',\'topic\',\'主題\',topOrd,ST.q.topic);\n  filterQ();\n}\nfunction updateQTopicChips(locTag){\n  const arr=locTag?Q.filter(x=>x.tags.includes(locTag)):Q;\n  const topicSet=new Set();\n  arr.forEach(x=>x.tags.forEach(t=>{if(!LOC_TAGS.has(t))topicSet.add(t)}));\n  const topOrd=[];\n  TOPIC_PRI.forEach(t=>{if(topicSet.has(t))topOrd.push(t)});\n  [...topicSet].filter(t=>!topOrd.includes(t)).sort().forEach(t=>topOrd.push(t));\n  const col=document.getElementById(\'fc-q-topic\');\n  if(!col)return;\n  const cur=ST.q.topic;\n  col.innerHTML=\'<div class="cw">\'\n    +topOrd.map(c=>\'<span class="ch\'+(c===cur?\' on\':\'\')+\'" data-type="q" data-key="topic" data-val="\'+escAttr(c)+\'" onclick="selChEl(this)">\'+esc(c)+\'</span>\').join(\'\')\n    +\'</div>\';\n  const tog=document.getElementById(\'ft-q-topic\');\n  if(tog){const cnt=tog.querySelector(\'.fcnt\');if(cnt)cnt.textContent=\'(\'+topOrd.length+\')\';}\n}\nfunction filterQ(){\n  const q=(document.getElementById(\'si-q\')||{value:\'\'}).value.trim().toLowerCase();\n  let arr=Q;\n  if(q)arr=arr.filter(x=>x.q.toLowerCase().includes(q));\n  if(ST.q.loc)arr=arr.filter(x=>x.tags.includes(ST.q.loc));\n  if(ST.q.topic)arr=arr.filter(x=>x.tags.includes(ST.q.topic));\n  document.getElementById(\'rc-q\').textContent=\'共 \'+arr.length+\' 筆問題\';\n  renderQ(arr);\n}\n\n// Helper: get city+district label for an item\nfunction itemLocLabel(item){\n  const city=(item.city_tags&&item.city_tags.length)?item.city_tags[0]:(item.city||\'\').split(\',\')[0].trim();\n  const dist=(item.district&&item.district!==\'有分店\')?item.district:\'\';\n  if(city&&dist)return city+\'·\'+dist;\n  if(city)return city;\n  return \'\';\n}\n\nfunction renderQ(arr){\n  document.getElementById(\'ql\').innerHTML=arr.slice(0,300).map((item,idx)=>{\n    const uid=\'q\'+idx;\n    const loc=item.tags.filter(t=>LOC_TAGS.has(t));\n    const topic=item.tags.filter(t=>!LOC_TAGS.has(t));\n    const hasLinks=(item.fi&&item.fi.length)||(item.hi&&item.hi.length)||(item.si&&item.si.length);\n    let secs=\'\';\n    if(!hasLinks){\n      secs+=\'<div style="margin-top:6px;padding-left:15px">\'\n        +\'<span class="notion-notice">📢 詳細內容請至notion版乾媽智囊團查看</span>\'\n        +\'</div>\';\n    }\n    if(item.fi&&item.fi.length){\n      const items=item.fi.map(i=>{\n        const fi=F[i];\n        const loc=itemLocLabel(fi);\n        const cat=fi.cat?CAT[fi.cat]||\'\':\'\';\n        return \'<div class="ci" data-name="\'+escAttr(fi.name)+\'" data-type="f" data-pg="2" onclick="ciJump(this)">\'\n          +\'<span class="ci-sq"></span>\'\n          +\'<span>\'+esc(fi.name)+\'</span>\'\n          +(cat?\'<span class="ci-cat">\'+esc(cat)+\'</span>\':\'\')\n          +(loc?\'<span class="ci-loc">\'+esc(loc)+\'</span>\':\'\')\n          +\'</div>\';\n      }).join(\'\');\n      secs+=mkCollapse(uid+\'f\',\'🍽️ 美食推薦\',item.fi.length,items);\n    }\n    if(item.hi&&item.hi.length){\n      const items=item.hi.map(i=>{\n        const hi=H[i];\n        const loc=itemLocLabel(hi);\n        return \'<div class="ci" data-name="\'+escAttr(hi.name)+\'" data-type="h" data-pg="3" onclick="ciJump(this)">\'\n          +\'<span class="ci-sq"></span>\'\n          +\'<span>\'+esc(hi.name)+\'</span>\'\n          +(loc?\'<span class="ci-loc">\'+esc(loc)+\'</span>\':\'\')\n          +\'</div>\';\n      }).join(\'\');\n      secs+=mkCollapse(uid+\'h\',\'🏨 住宿推薦\',item.hi.length,items);\n    }\n    if(item.si&&item.si.length){\n      const items=item.si.map(i=>{\n        const si=S[i];\n        const loc=itemLocLabel(si);\n        return \'<div class="ci" data-name="\'+escAttr(si.name)+\'" data-type="s" data-pg="4" onclick="ciJump(this)">\'\n          +\'<span class="ci-sq"></span>\'\n          +\'<span>\'+esc(si.name)+\'</span>\'\n          +(loc?\'<span class="ci-loc">\'+esc(loc)+\'</span>\':\'\')\n          +\'</div>\';\n      }).join(\'\');\n      secs+=mkCollapse(uid+\'s\',\'🗺️ 景點推薦\',item.si.length,items);\n    }\n    if(item.rqi&&item.rqi.length){\n      const items=item.rqi.map(i=>\'<div class="ci" data-qi="\'+i+\'" onclick="ciJumpQ(this)">\'\n        +\'<span class="ci-sq"></span><span>\'+esc(Q[i].q)+\'</span>\'\n        +\'</div>\').join(\'\');\n      secs+=mkCollapse(uid+\'r\',\'🔗 相關問題\',item.rqi.length,items);\n    }\n    return \'<div class="qc\'+(item.top?\' hot\':\'\')+\'" data-qi="\'+idx+\'">\'\n      +\'<div class="qt">\'+(item.top?\'<span style="font-size:14px">🔥</span>\':\'<span class="qsq"></span>\')+\'<span>\'+esc(item.q)+\'</span></div>\'\n      +\'<div class="qr2">\'+(item.date?\'<span class="qdate">\'+item.date+\'</span>\':\'\')+(item.top?\'<span class="qhot">🔥 熱門問題</span>\':\'\')+\'</div>\'\n      +\'<div class="qtags">\'\n      +loc.map(t=>\'<span class="qtag qtag-\'+(REGION_CLS[CITY_REGION[t]]||\'t\')+\'">\'+t+\'</span>\').join(\'\')\n      +topic.map(t=>\'<span class="qtag qtag-t">\'+t+\'</span>\').join(\'\')\n      +\'</div>\'+secs+\'</div>\';\n  }).join(\'\')||\'<div class="empty">沒有找到相關問題</div>\';\n}\n\n// ciJump/ciJumpQ: use data attributes, no escaping issues\nfunction ciJump(el){jumpToItem(el.dataset.name,el.dataset.type,parseInt(el.dataset.pg));}\nfunction ciJumpQ(el){jumpToQ(parseInt(el.dataset.qi));}\n\nfunction jumpToQ(idx){\n  goPage(1);\n  clearSI(\'q\');ST.q.loc=\'\';ST.q.topic=\'\';\n  setTimeout(()=>{\n    filterQ();\n    setTimeout(()=>{\n      const card=document.querySelector(\'#ql [data-qi="\'+idx+\'"]\');\n      if(card){card.scrollIntoView({behavior:\'smooth\',block:\'center\'});card.style.boxShadow=\'0 0 0 3px var(--gold)\';setTimeout(()=>card.style.boxShadow=\'\',1500);}\n    },300);\n  },350);\n}\n\n// ===== FOOD =====\nfunction init_f(){\n  const cities=getCities(F);\n  const catSet=new Set(F.map(x=>x.cat).filter(Boolean));\n  const catLabels=Object.keys(CAT).filter(k=>catSet.has(k)).map(k=>CAT[k]);\n  document.getElementById(\'fs-f\').innerHTML=\n    mkFGwithClr(\'f\',\'city\',\'縣市\',cities,ST.f.city)\n    +\'<div id="fs-f-sub"></div>\'\n    +mkFG(\'f\',\'cat\',\'美食分類\',catLabels,ST.f.cat);\n  filterF();\n}\nfunction rebuildFSub(city){\n  city=city||ST.f.city;\n  const el=document.getElementById(\'fs-f-sub\');if(!el)return;\n  if(!city||!FDM[city]){el.innerHTML=\'\';return;}\n  const dists=Object.keys(FDM[city]).sort();\n  const availCats=F_CAT_MAP[city]||new Set();\n  const catLabels=Object.keys(CAT).filter(k=>availCats.has(k)).map(k=>CAT[k]);\n  el.innerHTML=mkFG(\'f\',\'dist\',city+\'行政區\',dists,ST.f.dist);\n  const catCol=document.getElementById(\'fc-f-cat\');\n  const catTog=document.getElementById(\'ft-f-cat\');\n  if(catCol){\n    const cur=ST.f.cat;\n    catCol.innerHTML=\'<div class="cw">\'+catLabels.map(c=>\'<span class="ch\'+(c===cur?\' on\':\'\')+\'" data-type="f" data-key="cat" data-val="\'+escAttr(c)+\'" onclick="selChEl(this)">\'+esc(c)+\'</span>\').join(\'\')+\'</div>\';\n    if(catTog){const cnt=catTog.querySelector(\'.fcnt\');if(cnt)cnt.textContent=\'(\'+catLabels.length+\')\';}\n  }\n  const distCol=document.getElementById(\'fc-f-dist\');\n  const distTog=document.getElementById(\'ft-f-dist\');\n  if(distCol){distCol.style.display=\'block\';if(distTog)distTog.classList.add(\'op\');}\n}\nfunction filterF(){\n  const q=(document.getElementById(\'si-f\')||{value:\'\'}).value.trim().toLowerCase();\n  let arr=F;\n  if(q)arr=arr.filter(x=>(x.name||\'\').toLowerCase().includes(q)||(x.review||\'\').toLowerCase().includes(q));\n  if(ST.f.city)arr=arr.filter(x=>(x.city_tags&&x.city_tags.length?x.city_tags:[(x.city||\'\').split(\',\')[0].trim()]).includes(ST.f.city));\n  if(ST.f.dist)arr=arr.filter(x=>x.district===ST.f.dist);\n  if(ST.f.cat){const k=CAT_REV[ST.f.cat];if(k)arr=arr.filter(x=>x.cat===k);}\n  if(ST.f.city&&!ST.f.dist&&!ST.f.cat&&!q)arr=[...arr].sort((a,b)=>(a.district||\'\').localeCompare(b.district||\'\',\'zh\'));\n  document.getElementById(\'rc-f\').textContent=\'共 \'+arr.length+\' 筆美食\';\n  REND.f=arr;renderItems(\'fl\',arr,\'f\');\n}\n\n// ===== HOTEL =====\nfunction init_h(){\n  const cities=getCities(H);\n  document.getElementById(\'fs-h\').innerHTML=mkFGwithClr(\'h\',\'city\',\'縣市\',cities,ST.h.city)+\'<div id="fs-h-sub"></div>\';\n  filterH();\n}\nfunction rebuildHSub(city){\n  city=city||ST.h.city;\n  const el=document.getElementById(\'fs-h-sub\');if(!el)return;\n  if(!city||!HDM[city]){el.innerHTML=\'\';return;}\n  const dists=Object.keys(HDM[city]).sort();\n  el.innerHTML=mkFG(\'h\',\'dist\',city+\'行政區\',dists,ST.h.dist);\n  const distCol=document.getElementById(\'fc-h-dist\');\n  const distTog=document.getElementById(\'ft-h-dist\');\n  if(distCol){distCol.style.display=\'block\';if(distTog)distTog.classList.add(\'op\');}\n}\nfunction filterH(){\n  const q=(document.getElementById(\'si-h\')||{value:\'\'}).value.trim().toLowerCase();\n  let arr=H;\n  if(q)arr=arr.filter(x=>(x.name||\'\').toLowerCase().includes(q)||(x.review||\'\').toLowerCase().includes(q));\n  if(ST.h.city)arr=arr.filter(x=>(x.city_tags&&x.city_tags.length?x.city_tags:[(x.city||\'\').split(\',\')[0].trim()]).includes(ST.h.city));\n  if(ST.h.dist)arr=arr.filter(x=>x.district===ST.h.dist);\n  if(ST.h.city&&!ST.h.dist&&!q)arr=[...arr].sort((a,b)=>(a.district||\'\').localeCompare(b.district||\'\',\'zh\'));\n  document.getElementById(\'rc-h\').textContent=\'共 \'+arr.length+\' 筆住宿\';\n  REND.h=arr;renderItems(\'hl\',arr,\'h\');\n}\n\n// ===== SPOT =====\nfunction init_s(){\n  const cities=getCities(S);\n  document.getElementById(\'fs-s\').innerHTML=mkFGwithClr(\'s\',\'city\',\'縣市\',cities,ST.s.city)+\'<div id="fs-s-sub"></div>\';\n  filterS();\n}\nfunction rebuildSSub(city){\n  city=city||ST.s.city;\n  const el=document.getElementById(\'fs-s-sub\');if(!el)return;\n  if(!city||!SDM[city]){el.innerHTML=\'\';return;}\n  const dists=Object.keys(SDM[city]).sort();\n  el.innerHTML=mkFG(\'s\',\'dist\',city+\'行政區\',dists,ST.s.dist);\n  const distCol=document.getElementById(\'fc-s-dist\');\n  const distTog=document.getElementById(\'ft-s-dist\');\n  if(distCol){distCol.style.display=\'block\';if(distTog)distTog.classList.add(\'op\');}\n}\nfunction filterS(){\n  const q=(document.getElementById(\'si-s\')||{value:\'\'}).value.trim().toLowerCase();\n  let arr=S;\n  if(q)arr=arr.filter(x=>(x.name||\'\').toLowerCase().includes(q)||(x.review||\'\').toLowerCase().includes(q));\n  if(ST.s.city)arr=arr.filter(x=>(x.city_tags&&x.city_tags.length?x.city_tags:[(x.city||\'\').split(\',\')[0].trim()]).includes(ST.s.city));\n  if(ST.s.dist)arr=arr.filter(x=>x.district===ST.s.dist);\n  if(ST.s.city&&!ST.s.dist&&!q)arr=[...arr].sort((a,b)=>(a.district||\'\').localeCompare(b.district||\'\',\'zh\'));\n  document.getElementById(\'rc-s\').textContent=\'共 \'+arr.length+\' 筆景點\';\n  REND.s=arr;renderItems(\'sl\',arr,\'s\');\n}\n\n// ===== RENDER ITEMS =====\nfunction renderItems(cid,arr,type){\n  const shown=arr.slice(0,150);\n  document.getElementById(cid).innerHTML=shown.map((item,idx)=>{\n    const cardId=type+\'-c-\'+idx;\n    const catLabel=item.cat?CAT[item.cat]||item.cat:\'\';\n    const isBranch=item.district===\'有分店\';\n    const allCities=(item.city_tags&&item.city_tags.length)?item.city_tags:[(item.city||\'\').split(\',\')[0].trim()].filter(Boolean);const cityDisplay=allCities[0]||\'\';\n    const distStr=isBranch?\'有分店\':(item.district||\'\');\n    const ref=item.tiji||\'\';\n    let metaHtml=\'\';\n    allCities.forEach(c=>{metaHtml+=\'<span class="meta-city" style="margin-right:3px">\'+esc(c)+\'</span>\';});\n    if(distStr&&distStr!==cityDisplay)metaHtml+=\'<span style="margin-left:4px">\'+esc(distStr)+\'</span>\';\n    const catHtml=(type===\'f\'&&catLabel)?\'<div style="margin-top:3px"><span class="mcat">\'+esc(catLabel)+\'</span></div>\':\'\';\n    const refHtml=ref?\'<div style="margin-top:3px">\'+ref.split(\',\').map(r=>r.trim()).filter(Boolean).map(r=>\'<span class="ref-badge">\'+esc(r)+\'</span>\').join(\' \')+\'</div>\':\'\';\n    const links=[\n      item.google?\'<a class="lnk lnk-g" href="\'+item.google+\'" target="_blank">📍 Google Maps</a>\':\'\',\n      item.fb?\'<a class="lnk lnk-f" href="\'+item.fb+\'" target="_blank">FB</a>\':\'\',\n      item.ig?\'<a class="lnk lnk-i" href="\'+item.ig+\'" target="_blank">IG</a>\':\'\',\n      item.website?\'<a class="lnk lnk-w" href="\'+item.website+\'" target="_blank">官網</a>\':\'\',\n    ].filter(Boolean).join(\'\');\n    let qiHtml=\'\';\n    if(item.qi&&item.qi.length){\n      const qitems=item.qi.map(qi=>\'<div class="ci" data-qi="\'+qi+\'" onclick="ciJumpQ(this)"><span class="ci-sq"></span><span>\'+esc(Q[qi].q)+\'</span></div>\').join(\'\');\n      qiHtml=mkCollapse(cardId+\'q\',\'💬 出現在這些問題\',item.qi.length,qitems);\n    }\n    const nbHtml=buildNearby(item,type);\n    return \'<div class="ic" id="\'+cardId+\'" data-name="\'+escAttr(item.name||\'\')+\'">\'\n      +\'<div class="ih" data-did="\'+cardId+\'-d" data-bid="\'+cardId+\'-b" onclick="togDetEl(this)">\'\n      +\'<div style="flex:1"><div class="in">\'+esc(item.name||\'\')+\'</div>\'\n      +\'<div class="im">\'+metaHtml+\'</div>\'\n      +catHtml+refHtml+\'</div>\'\n      +\'<div class="ieb" id="\'+cardId+\'-b">▼</div>\'\n      +\'</div>\'\n      +\'<div class="idet" id="\'+cardId+\'-d">\'\n      +(item.review?\'<div class="rev">\'+esc(item.review)+\'</div>\':\'<div class="rev" style="color:var(--gray)">（無心得）</div>\')\n      +(links?\'<div class="lnks">\'+links+\'</div>\':\'\')\n      +qiHtml+nbHtml+\'</div></div>\';\n  }).join(\'\')||\'<div class="empty">沒有找到相關資料</div>\';\n  if(arr.length>150)document.getElementById(cid).innerHTML+=\'<div class="empty">（顯示前150筆，請用搜尋或篩選縮小範圍）</div>\';\n}\n\nfunction togDetEl(el){\n  const did=el.dataset.did,bid=el.dataset.bid;\n  const det=document.getElementById(did),btn=document.getElementById(bid);\n  const op=det.classList.toggle(\'op\');\n  if(btn)btn.textContent=op?\'▲\':\'▼\';\n}\n\n// ===== NEARBY =====\nfunction buildNearby(item,type){\n  const cities=item.city_tags&&item.city_tags.length?item.city_tags:[(item.city||\'\').split(\',\')[0].trim()];\n  const dist=item.district;\n  const title=dist&&dist!==\'有分店\'?\'📍 \'+dist+\'還有\':\'📍 附近還有\';\n  if(!dist||dist===\'有分店\'){\n    return \'<div class="csec"><div class="ctog" style="cursor:default"><span>\'+title+\'</span></div><div class="nb-none">【無】</div></div>\';\n  }\n  const city=cities[0]||\'\';\n  const k=city+\':\'+dist;\n  const buck=DIST_IDX[k]||{f:[],h:[],s:[]};\n  const self=item.name;\n  const nf=buck.f.filter(x=>x.name!==self);\n  const nh=buck.h.filter(x=>x.name!==self);\n  const ns=buck.s.filter(x=>x.name!==self);\n  const total=nf.length+nh.length+ns.length;\n  if(!total){\n    return \'<div class="csec"><div class="ctog" style="cursor:default"><span>\'+title+\'</span></div><div class="nb-none">【無】</div></div>\';\n  }\n  // Use a stable numeric ID for nearby collapse\n  const nbIdx=_nbCounter++;\n  function mkNbGroup(label,arr2,nt,pg){\n    if(!arr2.length)return\'\';\n    const LIMIT=5;\n    const uid=\'nbx\'+nbIdx+nt;\n    const shown=arr2.slice(0,LIMIT);\n    const extra=arr2.slice(LIMIT);\n    let html=\'<div style="margin-top:4px">\'\n      +\'<div style="font-size:11px;color:var(--gray);font-weight:600;margin-bottom:3px">\'+label+\'（\'+arr2.length+\'家）</div>\';\n    html+=shown.map(x=>\'<div class="ci" data-name="\'+escAttr(x.name)+\'" data-type="\'+nt+\'" data-pg="\'+pg+\'" onclick="ciJump(this)">▸ <span>\'+esc(x.name)+\'</span>\'+(nt===\'f\'&&x.cat?\'<span class="ci-cat">\'+(CAT[x.cat]||\'\')+\'</span>\':\'\')+\'</div>\').join(\'\');\n    if(extra.length){\n      html+=\'<div class="cbody" id="\'+uid+\'">\'+extra.map(x=>\'<div class="ci" data-name="\'+escAttr(x.name)+\'" data-type="\'+nt+\'" data-pg="\'+pg+\'" onclick="ciJump(this)">▸ <span>\'+esc(x.name)+\'</span>\'+(nt===\'f\'&&x.cat?\'<span class="ci-cat">\'+(CAT[x.cat]||\'\')+\'</span>\':\'\')+\'</div>\').join(\'\')+\'</div>\';\n      html+=\'<div class="nb-more" data-uid="\'+uid+\'" onclick="togNbX(this)">▶ 顯示更多 \'+extra.length+\' 家</div>\';\n    }\n    html+=\'</div>\';\n    return html;\n  }\n  const content=mkNbGroup(\'美食\',nf,\'f\',2)+mkNbGroup(\'住宿\',nh,\'h\',3)+mkNbGroup(\'景點\',ns,\'s\',4);\n  return mkCollapse(\'nb\'+nbIdx,title,total,content);\n}\nlet _nbCounter=0;\n\nfunction togNbX(btn){\n  const uid=btn.dataset.uid;\n  const el=document.getElementById(uid);if(!el)return;\n  const op=el.classList.toggle(\'op\');\n  btn.textContent=op?\'▲ 收起\':\'▶ 顯示更多\';\n}\n\n// ===== JUMP TO ITEM =====\nfunction jumpToItem(name,type,pg){\n  goPage(pg);\n  setTimeout(()=>{\n    Object.keys(ST[type]).forEach(k=>ST[type][k]=\'\');\n    clearSI(type);\n    if(type===\'f\'){rebuildFSub(\'\');filterF();}\n    else if(type===\'h\'){rebuildHSub(\'\');filterH();}\n    else if(type===\'s\'){rebuildSSub(\'\');filterS();}\n    setTimeout(()=>{\n      const listId={f:\'fl\',h:\'hl\',s:\'sl\'}[type];\n      const list=document.getElementById(listId);\n      if(!list)return;\n      let card=null;\n      list.querySelectorAll(\'[data-name]\').forEach(el=>{if(el.dataset.name===name)card=el;});\n      if(!card){\n        const idx2=REND[type].findIndex(x=>x.name===name);\n        if(idx2>=0)card=document.getElementById(type+\'-c-\'+idx2);\n      }\n      if(!card)return;\n      card.scrollIntoView({behavior:\'smooth\',block:\'center\'});\n      const det=document.getElementById(card.id+\'-d\');\n      const btn=document.getElementById(card.id+\'-b\');\n      if(det&&!det.classList.contains(\'op\')){det.classList.add(\'op\');if(btn)btn.textContent=\'▲\';}\n      card.style.boxShadow=\'0 0 0 3px var(--gold)\';\n      setTimeout(()=>card.style.boxShadow=\'\',1500);\n    },400);\n  },320);\n}\n\n// ===== HOME =====\nfunction initHome(){\n  document.getElementById(\'hgrid\').innerHTML=[\n    {lbl:\'問題\',cnt:Q.length,pg:1,ico:\'🔍\'},\n    {lbl:\'美食\',cnt:F.length,pg:2,ico:\'🍽️\'},\n    {lbl:\'住宿\',cnt:H.length,pg:3,ico:\'🏨\'},\n    {lbl:\'景點\',cnt:S.length,pg:4,ico:\'🗺️\'},\n  ].map(x=>\'<div class="hcard" data-pg="\'+x.pg+\'" onclick="goPage(parseInt(this.dataset.pg))">\'\n    +\'<div class="hico">\'+x.ico+\'</div>\'\n    +\'<div class="hlbl">\'+x.lbl+\'</div>\'\n    +\'<div class="hnum">\'+x.cnt.toLocaleString()+\'</div>\'\n    +\'</div>\').join(\'\');\n}\nfunction backTop(pgId){const el=document.getElementById(pgId);if(el)el.scrollTop=0;}\n\n// ===== GP =====\nfunction togGP(){\n  const b=document.getElementById(\'gp-body\'),a=document.getElementById(\'gp-arr\');\n  if(!b)return;\n  const op=b.classList.toggle(\'op\');\n  if(a)a.classList.toggle(\'op\',op);\n}\nfunction initGP(){\n  const gpData=(DB&&DB.gp)||[];\n  const el=document.getElementById(\'gp-count\');\n  const listEl=document.getElementById(\'gp-body\');\n  if(el)el.textContent=gpData.length.toLocaleString();\n  if(!listEl)return;\n  if(!gpData.length){listEl.innerHTML=\'<div style="font-size:12px;color:var(--gray);padding:4px 0">目前無進行中的團購（請至GitHub執行Actions同步最新資料）</div>\';return;}\n  const sorted=gpData.slice().sort((a,b)=>((a.countdown==null?9999:a.countdown)-(b.countdown==null?9999:b.countdown)));\n  listEl.innerHTML=sorted.map(item=>{\n    const days=item.countdown!=null?item.countdown:null;\n    const urg=(days!==null&&days<=3)?\' urg\':\'\';\n    return \'<div class="gp-item"><div class="gp-item-name">\'+esc(item.name||\'\')+\'</div>\'\n      +\'<div class="gp-item-row">\'\n      +(item.period?\'<span>📅 \'+esc(item.period)+\'</span>\':\'\')\n      +(days!==null?\'<span class="gp-cd\'+urg+\'">⏰ 剩\'+days+\'天</span>\':\'\')\n      +(item.url?\'<a class="gp-link" href="\'+item.url+\'" target="_blank">🔗 前往購買</a>\':\'\')\n      +\'</div></div>\';\n  }).join(\'\');\n}\n\n// ===== VISITORS =====\nvar VIS_PAGES=[\'home\',\'q\',\'f\',\'h\',\'s\'];\nfunction initVisitors(){\n  VIS_PAGES.forEach(function(pg,i){\n    var cnt=0;\n    try{cnt=parseInt(localStorage.getItem(\'vis_\'+pg)||\'0\');}catch(e){}\n    try{if(!sessionStorage.getItem(\'vss_\'+pg)){cnt++;localStorage.setItem(\'vis_\'+pg,cnt);sessionStorage.setItem(\'vss_\'+pg,\'1\');}}catch(e){}\n    const el=document.getElementById(\'vis-\'+i);\n    if(el)el.textContent=\'• 有\'+cnt+\'人到訪\';\n  });\n}\nfunction onPageVisit(i){\n  if(i<0||i>=VIS_PAGES.length)return;\n  try{\n    if(!sessionStorage.getItem(\'vss_\'+VIS_PAGES[i])){\n      const cnt=parseInt(localStorage.getItem(\'vis_\'+VIS_PAGES[i])||\'0\')+1;\n      localStorage.setItem(\'vis_\'+VIS_PAGES[i],cnt);\n      sessionStorage.setItem(\'vss_\'+VIS_PAGES[i],\'1\');\n      const el=document.getElementById(\'vis-\'+i);\n      if(el)el.textContent=\'• 有\'+cnt+\'人到訪\';\n    }\n  }catch(e){}\n}\n\n// ===== INIT =====\ninitHome();\nwindow.addEventListener(\'load\',function(){initVisitors();initGP();});\n</script>\n</body>\n</html>'
